"""Generated file writing policy."""

from pathlib import Path
import shutil

from pygodot.errors import BuildError

GENERATED_MARKER = "Generated by pygodot"
LEGACY_GENERATED_MARKERS = ("Generated by pygodot prototype",)


class GeneratedFileWriter:
    """Writes generated files while preserving manual ownership boundaries."""

    def __init__(self, project_dir: Path, *, allow_overwrite_unmarked: bool = False) -> None:
        self.project_dir = project_dir
        self.allow_overwrite_unmarked = allow_overwrite_unmarked

    def write_text(self, relative_path: Path, content: str, *, mark_generated: bool = True) -> Path:
        if relative_path.is_absolute():
            raise BuildError(f"Generated file path must be relative: {relative_path}.")

        destination = self.project_dir / relative_path
        destination.parent.mkdir(parents=True, exist_ok=True)

        generated_content = _with_marker(relative_path, content) if mark_generated else content.rstrip() + "\n"
        if destination.exists():
            existing = destination.read_text(encoding="utf-8")
            if not self.allow_overwrite_unmarked and GENERATED_MARKER not in existing and not any(
                marker in existing for marker in LEGACY_GENERATED_MARKERS
            ):
                raise BuildError(f"Refusing to overwrite manual file: {destination}.")

        destination.write_text(generated_content, encoding="utf-8")
        return destination

    def copy_file(self, source: Path, relative_path: Path) -> Path:
        if relative_path.is_absolute():
            raise BuildError(f"Copied file path must be relative: {relative_path}.")
        if not source.is_file():
            raise BuildError(f"Cannot copy missing resource: source={source}, destination={relative_path}.")

        destination = self.project_dir / relative_path
        destination.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(source, destination)
        return destination


def _with_marker(relative_path: Path, content: str) -> str:
    content = content.rstrip() + "\n"
    if content.startswith(";") or content.startswith("#"):
        return content
    comment = "#" if relative_path.suffix == ".gd" else ";"
    return f"{comment} {GENERATED_MARKER}. Do not edit by hand.\n\n{content}"
